#include <bits/stdc++.h>using namespace std; void solve() {    int n;    cin >> n;    string s;    cin >> s;        s = "0" + s + "0";         int k = 0;     int z = 0;      for (char c : s) {        if (c == '1') {            k += z / 3;            k++;            z = 0;        } else {            z++;        }    }        k += z / 3;     cout << k << "\n";} int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        solve();    }    return 0;}